parameters.jsCode:
const lastMessage = items[0].json.messages?.slice(-1)[0]?.content 
                 || items[0].json.output 
                 || '';

const parsed = JSON.parse(lastMessage);

if (parsed.pay === true || parsed.pay === "true" || parsed.pay === 1) {
  const amount = Number(parsed.amount);

  if (Number.isInteger(amount) && amount >= 1 && amount <= 1000000) {
    return [{ 
      json: { 
        pay: true,                    
        amount: amount, 
        reason: parsed.reason || 'No reason given' 
      } 
    }];
  } else {
    return [{ 
      json: { 
        pay: false, 
        amount: amount,
        reason: parsed.reason || 'No reason given',
        message: `Payment amount ${amount} sats is outside allowed range (1 to 1,000,000 sats)` 
      } 
    }];
  }
}

// Not a valid payment decision
return [{ 
  json: { 
    pay: false, 
    message: lastMessage,
    reason: "Invalid or missing payment JSON from Agent A" 
  } 
}];

