parameters.jsCode:
const input = items[0].json;

// Debug: show what we actually received
console.log("Raw input to Clean Rejection Data:", JSON.stringify(input, null, 2));

// Extract raw output from Agent-A
let rawOutput = input.output || input.message || input.raw_message || '';

// Try to parse if it's a stringified JSON
let parsed = {};
if (typeof rawOutput === 'string' && rawOutput.trim().startsWith('{')) {
  try {
    parsed = JSON.parse(rawOutput);
  } catch (e) {
    try {
      const cleaned = rawOutput.replace(/^"|"$/g, '').replace(/\\"/g, '"');
      parsed = JSON.parse(cleaned);
    } catch (e2) {}
  }
}

// Use the most reliable amount source possible
const amount = Number(
  input.amount || 
  parsed.amount || 
  input["amount"] || 
  0
);

return [{
  json: {
    pay: false,
    amount: amount,
    reason: parsed.reason || input.reason || "No reason provided",
    message: parsed.reason || input.message || rawOutput || "No message from Agent A",
    status: "rejected",
    rejection_reason: amount < 1 
      ? "Payment amount is too small (must be at least 1 sat)" 
      : amount > 1000000 
        ? "Payment amount exceeds maximum limit (1,000,000 sats)" 
        : "Agent A did not approve the payment"
  }
}];
